#include <stdio.h>
#include <stdint.h>
int64_t mod_inverse(int64_t a, int64_t m) {
    int64_t m0 = m;
    int64_t y = 0, x = 1;
    if (m == 1)
        return 0;
    while (a > 1) {
        int64_t q = a / m;
        int64_t t = m;
        m = a % m, a = t;
        t = y;
        y = x - q * y;
        x = t;
    }
    if (x < 0)
        x += m0;
    return x;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int64_t N;
        scanf("%lld", &N);
        int64_t mod = 1000000007;
        int64_t ans = (N * mod_inverse(26, mod)) % mod;
        printf("%lld\n", ans);
    }
    return 0;
}

